const items = $input.all();

// Each item came from one branch's Set node
const find = (key) => {
  const match = items.find(i => i.json[key] !== undefined);
  return match ? match.json[key] : 'Failed';
};

const emailStatus    = find('emailStatus');
const calendarStatus = find('calendarStatus');
const slackStatus    = find('slackStatus');
const hubspotStatus  = find('hubspotStatus');
const formData       = $('Clean Form data').first().json;

const hasFailed = [emailStatus,calendarStatus,
  slackStatus,hubspotStatus].some(s => s === 'Failed');

return [{json: {
  Timestamp: new Date().toISOString(),
  'Client Name': `${formData['First Name']} ${formData['Last Name']}`,
  Email: formData.Email,
  Industry: formData.Industry,
  'Email Sent': emailStatus,
  'Calendar Created': calendarStatus,
  'Slack Notified': slackStatus,
  HubSpot: hubspotStatus,
  Status: hasFailed ? 'Partial' : 'Completed'
}}];

